document.addEventListener('DOMContentLoaded', () => {
    
    // STICKY HEADER
    const header = document.getElementById('main-header');
    
    const handleScroll = () => {
        if (window.scrollY > 50) {
            header.classList.add('scrolled');
        } else {
            header.classList.remove('scrolled');
        }
    };
    
    window.addEventListener('scroll', handleScroll);
    handleScroll(); // Initial check

    // MOBILE DRAWER MENU
    const mobileToggleBtn = document.getElementById('mobile-toggle-btn');
    const drawerCloseBtn = document.getElementById('drawer-close-btn');
    const mobileDrawer = document.getElementById('mobile-drawer');
    const drawerOverlay = document.getElementById('drawer-overlay');
    const drawerLinks = document.querySelectorAll('.drawer-link');

    const openDrawer = () => {
        mobileDrawer.classList.add('open');
        drawerOverlay.classList.add('active');
        document.body.style.overflow = 'hidden'; // Prevent body scroll
    };

    const closeDrawer = () => {
        mobileDrawer.classList.remove('open');
        drawerOverlay.classList.remove('active');
        document.body.style.overflow = ''; // Restore body scroll
    };

    mobileToggleBtn.addEventListener('click', openDrawer);
    drawerCloseBtn.addEventListener('click', closeDrawer);
    drawerOverlay.addEventListener('click', closeDrawer);

    drawerLinks.forEach(link => {
        link.addEventListener('click', () => {
            closeDrawer();
        });
    });

    // ACTIVE NAV SCROLL SPY
    const sections = document.querySelectorAll('section');
    const navLinks = document.querySelectorAll('.nav-link');
    
    const activeLinkOnScroll = () => {
        let currentSectionId = 'home';
        
        sections.forEach(section => {
            const sectionTop = section.offsetTop;
            const sectionHeight = section.offsetHeight;
            
            // Adjust threshold offset for sticky nav (approx. 100px)
            if (window.scrollY >= (sectionTop - 150)) {
                currentSectionId = section.getAttribute('id');
            }
        });

        // Main Desktop Nav Spy
        navLinks.forEach(link => {
            link.classList.remove('active');
            if (link.getAttribute('href') === `#${currentSectionId}`) {
                link.classList.add('active');
            }
        });

        // Mobile Drawer Nav Spy
        drawerLinks.forEach(link => {
            link.classList.remove('active');
            if (link.getAttribute('href') === `#${currentSectionId}`) {
                link.classList.add('active');
            }
        });
    };

    window.addEventListener('scroll', activeLinkOnScroll);
    activeLinkOnScroll(); // Initial execution

    // CONTACT FORM HANDLER WITH TOAST
    const contactForm = document.getElementById('contact-form');
    const toast = document.getElementById('toast-notification');
    const toastCloseBtn = document.getElementById('btn-toast-close');
    let toastTimeout;

    const showToast = () => {
        clearTimeout(toastTimeout);
        toast.classList.add('show');
        
        // Auto hide after 5 seconds
        toastTimeout = setTimeout(() => {
            hideToast();
        }, 5000);
    };

    const hideToast = () => {
        toast.classList.remove('show');
    };

    if (contactForm) {
        contactForm.addEventListener('submit', (e) => {
            e.preventDefault();
            
            // Simulate form submission logic (e.g. AJAX / fetch)
            const formData = new FormData(contactForm);
            console.log('Form Submitted successfully:', Object.fromEntries(formData.entries()));

            // Clear input fields
            contactForm.reset();
            
            // Show premium success notification
            showToast();
        });
    }

    if (toastCloseBtn) {
        toastCloseBtn.addEventListener('click', hideToast);
    }

    // LIGHT/DARK THEME TOGGLE WITH STARRY SKY
    const themeToggleBtn = document.getElementById('theme-toggle-btn');
    const drawerThemeToggleBtn = document.getElementById('drawer-theme-toggle-btn');
    const body = document.body;

    const initStars = () => {
        const container = document.getElementById('stars-container');
        if (!container) return;
        
        container.innerHTML = '';
        if (body.classList.contains('light-mode')) return;
        
        const starCount = 85;
        for (let i = 0; i < starCount; i++) {
            const star = document.createElement('div');
            star.classList.add('star');
            
            const sizeRand = Math.random();
            if (sizeRand < 0.15) {
                star.classList.add('star-large');
            } else if (sizeRand > 0.8) {
                star.classList.add('star-small');
            }
            
            star.style.top = `${Math.random() * 100}%`;
            star.style.left = `${Math.random() * 100}%`;
            
            star.style.animationDelay = `${Math.random() * 4}s`;
            star.style.animationDuration = `${2 + Math.random() * 4}s`;
            
            container.appendChild(star);
        }
    };

    const updateThemeToggleIcons = (isLight) => {
        const iconClass = isLight ? 'fa-sun' : 'fa-moon';
        const otherClass = isLight ? 'fa-moon' : 'fa-sun';
        
        [themeToggleBtn, drawerThemeToggleBtn].forEach(btn => {
            if (btn) {
                const icon = btn.querySelector('i');
                if (icon) {
                    icon.classList.remove(otherClass, 'fa-solid', 'fa-regular');
                    icon.classList.add('fa-solid', iconClass);
                }
            }
        });
    };

    const setTheme = (isLight) => {
        if (isLight) {
            body.classList.add('light-mode');
            localStorage.setItem('theme', 'light');
        } else {
            body.classList.remove('light-mode');
            localStorage.setItem('theme', 'dark');
        }
        updateThemeToggleIcons(isLight);
        initStars();
    };

    const toggleTheme = () => {
        const isCurrentLight = body.classList.contains('light-mode');
        setTheme(!isCurrentLight);
    };

    if (themeToggleBtn) {
        themeToggleBtn.addEventListener('click', toggleTheme);
    }
    if (drawerThemeToggleBtn) {
        drawerThemeToggleBtn.addEventListener('click', toggleTheme);
    }

    const savedTheme = localStorage.getItem('theme');
    const prefersLight = window.matchMedia('(prefers-color-scheme: light)').matches;
    const initialLight = savedTheme === 'light' || (!savedTheme && prefersLight);
    
    setTheme(initialLight);

    // BASE64 FORCED PDF DOWNLOADER
    const forceDownloadPDF = (filename) => {
        const link = document.createElement('a');
        link.href = 'data:application/octet-stream;base64,' + pdfBase64.trim();
        link.setAttribute('download', filename);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

    const downloadButtons = document.querySelectorAll('#btn-hero-cv, #btn-download-cv');
    downloadButtons.forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.preventDefault();
            const filename = btn.getAttribute('download') || 'SithumiSanulya_CV.pdf';
            forceDownloadPDF(filename);
        });
    });
});


const pdfBase64 = "";
